  ]
};

/**
 * Executes a call across multiple model tiers before falling back to local.
 */
async function callNeuralTier<T>(
  cloudFn: (model: string) => Promise<T>, 
  fallback: () => T
): Promise<T> {
  if (isCloudQuotaExhausted) return fallback();

  const models = ['gemini-3-flash-preview', 'gemini-flash-lite-latest'];

  for (const model of models) {
    try {
      return await cloudFn(model);
    } catch (error: any) {
      const errStr = (error.message || JSON.stringify(error)).toUpperCase();
      const isHardQuota = errStr.includes("429") || errStr.includes("QUOTA") || errStr.includes("RESOURCE_EXHAUSTED");

      if (isHardQuota) {
        console.warn(`Model ${model} exhausted. Attempting next tier...`);
        if (model === models[models.length - 1]) {
          isCloudQuotaExhausted = true;
          throw new Error("QUOTA_EXHAUSTED_DAILY");
        }
        continue; // Try next model
      }
      throw error; // Unexpected error
    }
  }
  return fallback();
}

export const getIsCloudExhausted = () => isCloudQuotaExhausted;

/**
 * Neural Suggestion Engine with Multi-Model Fallback
 */
export async function getFieldSuggestion(field: string, currentValue: string, context: any): Promise<string> {
  const getLocal = () => {
    const options = LOCAL_LIBRARY[field] || ["New Creative Wave", "Neural Flux"];
    return options[Math.floor(Math.random() * options.length)];
  };

  try {
    return await callNeuralTier(async (modelName) => {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
      const systemInstruction = `You are the SoundWeave Studio assistant. Return ONLY a single text suggestion for the field: ${field}. No quotes.`;
      const response = await ai.models.generateContent({
        model: modelName,
        contents: `Suggestion for "${field}". Progress: ${JSON.stringify(context)}`,
        config: { systemInstruction, temperature: 0.9 }
      });
      return response.text.trim().replace(/^["']|["']$/g, '');
    }, getLocal);
  } catch (e: any) {
    return getLocal();
  }
}

/**
 * Intent Interpreter with Multi-Model Fallback
 */
export async function interpretIntent(project: any) {
  const getLocal = () => ({
    mood: "Adaptive",
    energyLevel: 70,
    atmosphere: "Studio Default",
    technicalNotes: "Offline local engine active. Using optimized generic synthesis parameters."
  });

  try {
    return await callNeuralTier(async (modelName) => {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
      const response = await ai.models.generateContent({
        model: modelName,
        contents: `Analyze intent JSON: ${JSON.stringify(project)}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              mood: { type: Type.STRING },
              energyLevel: { type: Type.NUMBER },
              technicalNotes: { type: Type.STRING }
            },
            required: ["mood", "energyLevel", "technicalNotes"]
          }
        }
      });
      return JSON.parse(response.text.trim());
    }, getLocal);
  } catch (e: any) {
    return getLocal();
  }
}

/**
 * Visual Synthesis (Veo) - No local fallback for video, but handles quota
 */
export async function generateVeoVideo(style: string, genre: string, prompt: string): Promise<string> {
  if (isCloudQuotaExhausted) throw new Error("QUOTA_EXHAUSTED_DAILY");

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: `Style: ${style}. Cinematic ${genre} music visual. ${prompt}`,
    config: { numberOfVideos: 1, resolution: '720p', aspectRatio: '16:9' }
  });

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 8000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  if (!response.ok) throw new Error("Video Download Error");
  const blob = await response.blob();
  return URL.createObjectURL(blob);
}

import React, { useState, useEffect } from 'react';
import { 
  AppState, 
  UserSession, 
  CreationMode, 
  ProjectRecord, 
  Status, 
  TrackData,
  SuggestionState
} from './types';
import { db } from './services/dbService';
import { getFieldSuggestion, interpretIntent, generateVeoVideo, getIsCloudExhausted } from './services/geminiService';
import { generateSynthesizedAudio } from './services/audioService';

const GENRES = ["Ambient", "Cyberpunk", "Deep House", "Industrial", "Jazz Fusion", "Lo-Fi", "Neo-Classical", "Orchestral", "Phonk", "Synthwave", "Techno"];
const LANGUAGES = ["Instrumental", "English", "Japanese", "French", "Spanish", "German", "Korean"];

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.KEY_SETUP);
  const [session, setSession] = useState<UserSession | null>(null);
  const [projects, setProjects] = useState<ProjectRecord[]>([]);
  const [activeTab, setActiveTab] = useState<AppState>(AppState.HOME);

  // Form State
  const [mode, setMode] = useState<CreationMode>(CreationMode.SINGLE);
  const [numSongs, setNumSongs] = useState(3);
  const [title, setTitle] = useState('');
  const [prompt, setPrompt] = useState('');
  const [selectedGenres, setSelectedGenres] = useState<string[]>([]);
  const [duration, setDuration] = useState(120);
  const [vocalLangs, setVocalLangs] = useState<string[]>(["Instrumental"]);
  const [lyrics, setLyrics] = useState('');
  const [videoEnabled, setVideoEnabled] = useState(false);
  const [videoStyle, setVideoStyle] = useState('');

  // UI State
  const [isProcessing, setIsProcessing] = useState(false);
  const [suggestingField, setSuggestingField] = useState<string | null>(null);
  const [suggestion, setSuggestion] = useState<SuggestionState | null>(null);
  const [globalError, setGlobalError] = useState<{ message: string; isQuota: boolean; isHardLimit: boolean } | null>(null);
  const [isQuotaExhausted, setIsQuotaExhausted] = useState(false);

  useEffect(() => {
    const init = async () => {
      // @ts-ignore
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (hasKey) {
        const s = db.getSession();
        if (s) {
          setSession(s);
          setAppState(AppState.HOME);
          setProjects(db.getProjects(s.id));
        } else {
          setAppState(AppState.AUTH);
        }
      } else {
        setAppState(AppState.KEY_SETUP);
      }
    };
    init();
  }, []);

  const handleKeySetup = async () => {
    setGlobalError(null);
    setIsQuotaExhausted(false);
    // @ts-ignore
    await window.aistudio.openSelectKey();
    const s = db.getSession();
    if (s) {
      setSession(s);
      setAppState(AppState.HOME);
      setProjects(db.getProjects(s.id));
    } else {
      setAppState(AppState.AUTH);
    }
  };

  const requestSuggestion = async (field: string, currentValue: string) => {
    if (suggestingField) return;
    setSuggestingField(field);
    setGlobalError(null);
    try {
      const context = { mode, title, prompt, selectedGenres, vocalLangs, lyrics, videoStyle };
      const suggestedText = await getFieldSuggestion(field, currentValue, context);
      setSuggestion({ field, original: currentValue, suggested: suggestedText, isActive: true });

      // Sync local state with service state
      if (getIsCloudExhausted()) {
        setIsQuotaExhausted(true);
      }
    } catch (e: any) {
      setIsQuotaExhausted(true);
      setGlobalError({ 
        message: "Neural Cloud limited. Local Preset Engine engaged.", 
        isQuota: true,
        isHardLimit: true
      });
      // Silent fallback handled by getFieldSuggestion returning local result
    } finally {
      setSuggestingField(null);
    }
  };

  const applySuggestion = () => {
    if (!suggestion) return;
    const { field, suggested } = suggestion;
    if (field === 'title') setTitle(suggested);
    if (field === 'prompt') setPrompt(suggested);
    if (field === 'lyrics') setLyrics(suggested);
    if (field === 'videoStyle') setVideoStyle(suggested);
    if (field === 'numSongs') setNumSongs(parseInt(suggested) || 3);
    setSuggestion(null);
  };

  const startGeneration = async () => {
    if (!title || !prompt || selectedGenres.length === 0) {
      alert("Please provide Title, Creative Brief, and Genres.");
      return;
    }

    setIsProcessing(true);
    setGlobalError(null);
    const projectId = crypto.randomUUID();
    const newProject: ProjectRecord = {
      id: projectId,
      userId: session!.id,
      mode, title, prompt, 
      genres: selectedGenres,
      durationSeconds: duration,
      vocalLanguages: vocalLangs,
      lyrics,
      artistReferences: [],
      videoEnabled,
      videoStyle,
      tracks: [],
      status: Status.PROCESSING,
      createdAt: Date.now()
    };

    try {
      const intent = await interpretIntent(newProject);
      newProject.metadata = intent;

      const trackCount = mode === CreationMode.ALBUM ? numSongs : 1;
      const tracks: TrackData[] = [];

      for (let i = 0; i < trackCount; i++) {
        const audioUrl = await generateSynthesizedAudio(duration);
        let videoUrl = undefined;
        if (videoEnabled && !isQuotaExhausted) {
          try {
            videoUrl = await generateVeoVideo(videoStyle || "Minimalist", selectedGenres[0], prompt);
          } catch (veoErr) {
            console.warn("Video failed, continuing with audio only.");
          }
        }
        tracks.push({
          id: crypto.randomUUID(),
          title: mode === CreationMode.ALBUM ? `${title} - Part ${i+1}` : title,
          audioUrl,
          videoUrl,
          duration
        });
      }

      newProject.tracks = tracks;
      newProject.status = Status.COMPLETED;
      await db.saveProject(newProject);
      setProjects(prev => [newProject, ...prev]);
      setActiveTab(AppState.DASHBOARD);
    } catch (e: any) {
      newProject.status = Status.FAILED;
      await db.saveProject(newProject);
      setGlobalError({ message: "Neural Synthesis Interrupted. Try a shorter track.", isQuota: false, isHardLimit: false });
    } finally {
      setIsProcessing(false);
      setIsQuotaExhausted(getIsCloudExhausted());
    }
  };

  if (appState === AppState.KEY_SETUP) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-deep p-6">
        <div className="glass w-full max-w-lg p-12 rounded-[3rem] space-y-10 border border-white/5 shadow-2xl text-center">
          <div className="space-y-4">
            <h1 className="text-4xl font-black tracking-tighter text-white">Neural Uplink</h1>
            <p className="text-zinc-500 text-sm font-medium leading-relaxed">SoundWeave requires a Google Cloud API key for high-fidelity synthesis.</p>
          </div>
          <button onClick={handleKeySetup} className="w-full bg-brand py-6 rounded-2xl font-black text-xs uppercase tracking-widest hover:brightness-110 active:scale-95 transition-all shadow-xl shadow-brand/20">Configure API Key</button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-deep font-sans selection:bg-brand selection:text-white">
      {/* Sidebar Nav */}
      <aside className="w-80 border-r border-white/5 bg-[#070707] flex flex-col sticky top-0 h-screen">
        <div className="p-10">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 rounded-lg bg-brand flex items-center justify-center font-black text-white italic">S</div>
            <h2 className="text-2xl font-black tracking-tighter text-white">SOUNDWEAVE</h2>
          </div>
        </div>
        <nav className="flex-1 px-6 space-y-1">
          <NavItem active={activeTab === AppState.HOME} onClick={() => setActiveTab(AppState.HOME)} icon="🏠" label="Home" />
          <NavItem active={activeTab === AppState.CREATE} onClick={() => setActiveTab(AppState.CREATE)} icon="✨" label="Studio" />
          <NavItem active={activeTab === AppState.DASHBOARD} onClick={() => setActiveTab(AppState.DASHBOARD)} icon="📂" label="Workspace" />
        </nav>

        <div className="px-6 py-4">
           <div className={`p-4 rounded-2xl border transition-all ${isQuotaExhausted ? 'bg-amber-500/10 border-amber-500/20 shadow-[0_0_20px_rgba(245,158,11,0.05)]' : 'bg-green-500/5 border-green-500/10'}`}>
              <div className="flex items-center justify-between mb-2">
                 <span className="text-[9px] font-black uppercase tracking-widest text-zinc-500">Neural Link</span>
                 <div className={`w-2 h-2 rounded-full ${isQuotaExhausted ? 'bg-amber-500 animate-pulse' : 'bg-green-500'}`} />
              </div>
              <p className={`text-[10px] font-bold uppercase tracking-tight ${isQuotaExhausted ? 'text-amber-400' : 'text-zinc-400'}`}>
                 {isQuotaExhausted ? 'Local Presets Active' : 'Hybrid Cloud Active'}
              </p>
           </div>
        </div>

        <div className="p-8 border-t border-white/5 space-y-6">
          <button onClick={handleKeySetup} className="w-full text-[10px] uppercase font-black py-3 border border-brand/20 rounded-xl bg-brand/5 text-brand hover:text-white transition-all">Credentials</button>
          <div className="flex items-center gap-4 group">
            <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-brand to-blue-600 flex items-center justify-center font-black text-xl shadow-lg shadow-brand/20">{session?.name?.[0]}</div>
            <div className="min-w-0">
              <p className="text-sm font-black truncate text-white">{session?.name}</p>
              <p className="text-[10px] font-mono text-zinc-600 truncate">{session?.mobile}</p>
            </div>
          </div>
        </div>
      </aside>

      {/* Content Area */}
      <main className="flex-1 overflow-y-auto">
        <div className="max-w-6xl mx-auto p-16 relative">

          {globalError && (
            <div className="mb-10 animate-in slide-in-from-top-4 duration-500">
               <div className={`glass border-l-4 p-8 rounded-[2rem] flex items-center justify-between gap-6 ${globalError.isQuota ? 'border-amber-500 bg-amber-500/5' : 'border-red-500 bg-red-500/5'}`}>
                  <div className="flex items-center gap-6">
                     <span className="text-3xl">{globalError.isHardLimit ? '📚' : '⚠️'}</span>
                     <div className="space-y-1">
                        <p className={`text-sm font-black uppercase tracking-widest ${globalError.isQuota ? 'text-amber-400' : 'text-red-400'}`}>{globalError.message}</p>
                        <p className="text-[10px] text-zinc-500 font-bold">The SoundWeave Local Library will now provide deterministic creative suggestions.</p>
                     </div>
                  </div>
                  <div className="flex items-center gap-6 shrink-0">
                    <button onClick={handleKeySetup} className="bg-brand px-6 py-3 rounded-xl text-[10px] font-black text-white uppercase tracking-widest shadow-xl shadow-brand/20">Update Uplink</button>
                    <button onClick={() => setGlobalError(null)} className="text-[10px] font-black text-zinc-600 uppercase">Dismiss</button>
                  </div>
               </div>
            </div>
          )}

          {activeTab === AppState.HOME && (
            <div className="space-y-16 py-10 animate-in fade-in duration-1000">
              <div className="space-y-4">
                <h1 className="text-8xl font-black tracking-tighter leading-none">
                  Neural <br/><span className="text-brand">Soundscapes.</span>
                </h1>
                <p className="text-zinc-500 text-lg max-w-xl font-medium">Professional-grade AI music synthesis for modern creators.</p>
              </div>
              <div className="grid grid-cols-2 gap-8">
                <button onClick={() => setActiveTab(AppState.CREATE)} className="glass p-12 rounded-[3rem] text-left hover:border-brand/40 transition-all group relative overflow-hidden">
                  <h3 className="text-3xl font-black mb-3">Initiate Project</h3>
                  <p className="text-zinc-500 text-sm font-medium">Construct new audio signatures from creative prompts.</p>
                </button>
                <button onClick={() => setActiveTab(AppState.DASHBOARD)} className="glass p-12 rounded-[3rem] text-left hover:border-brand/40 transition-all group relative overflow-hidden">
                  <h3 className="text-3xl font-black mb-3">Workspace</h3>
                  <p className="text-zinc-500 text-sm font-medium">Audit existing productions and archives.</p>
                </button>
              </div>
            </div>
          )}

          {activeTab === AppState.CREATE && (
            <div className={`space-y-16 animate-in fade-in duration-700 ${isProcessing ? 'pointer-events-none' : ''}`}>
              <header className="flex justify-between items-end border-b border-white/5 pb-10">
                <div>
                  <h2 className="text-5xl font-black tracking-tighter">Studio Deck</h2>
                  <p className="text-zinc-500 font-bold uppercase text-[10px] tracking-[0.4em] mt-2">New Neural Synthesis Intent</p>
                </div>
                {isProcessing && (
                  <div className="flex items-center gap-4 bg-brand/10 border border-brand/20 px-6 py-3 rounded-2xl">
                    <span className="w-2 h-2 rounded-full bg-brand animate-ping"></span>
                    <span className="text-[10px] font-black text-brand uppercase tracking-widest">Synthesizing Signal...</span>
                  </div>
                )}
              </header>

              <div className="grid grid-cols-12 gap-16">
                <div className="col-span-12 lg:col-span-8 space-y-16">
                  <section className="space-y-10">
                    <Field label="Project Title" value={title} onChange={setTitle} onSuggest={() => requestSuggestion('title', title)} suggesting={suggestingField === 'title'} exhausted={isQuotaExhausted} placeholder="e.g. Midnight Drift" />
                    <Field label="Creative Brief" isTextArea value={prompt} onChange={setPrompt} onSuggest={() => requestSuggestion('prompt', prompt)} suggesting={suggestingField === 'prompt'} exhausted={isQuotaExhausted} placeholder="Describe the sonic atmosphere..." />
                  </section>

                  <section className="space-y-8">
                    <label className="text-[10px] font-black uppercase tracking-[0.3em] text-zinc-600 px-1">Genre Constraints</label>
                    <div className="flex flex-wrap gap-2">
                      {GENRES.map(g => (
                        <button key={g} onClick={() => setSelectedGenres(prev => prev.includes(g) ? prev.filter(x => x !== g) : [...prev, g])} className={`px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest border transition-all ${selectedGenres.includes(g) ? 'bg-brand border-brand text-white' : 'border-white/5 text-zinc-700 hover:text-zinc-400'}`}>
                          {g}
                        </button>
                      ))}
                    </div>
                  </section>

                  <section className="grid grid-cols-2 gap-8">
                    <div className="space-y-6">
                      <label className="text-[10px] font-black uppercase tracking-[0.3em] text-zinc-600 px-1">Linguistic Bias</label>
                      <div className="grid grid-cols-2 gap-2">
                        {LANGUAGES.map(l => (
                          <button key={l} onClick={() => setVocalLangs(prev => prev.includes(l) ? prev.filter(x => x !== l) : [...prev, l])} className={`px-4 py-4 rounded-xl border text-[9px] font-black uppercase tracking-tighter transition-all ${vocalLangs.includes(l) ? 'border-brand bg-brand/5 text-white' : 'border-white/5 text-zinc-800'}`}>
                            {l}
                          </button>
                        ))}
                      </div>
                    </div>
                    <Field label="Lyrics / Narrative" isTextArea value={lyrics} onChange={setLyrics} onSuggest={() => requestSuggestion('lyrics', lyrics)} suggesting={suggestingField === 'lyrics'} exhausted={isQuotaExhausted} />
                  </section>
                </div>

                <div className="col-span-12 lg:col-span-4 space-y-12">
                   <section className="glass p-10 rounded-[2.5rem] space-y-8">
                      <div className="flex justify-between items-end">
                        <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600">Duration</label>
                        <div className="text-3xl font-black text-brand tracking-tighter">{Math.floor(duration/60)}<span className="text-xs text-zinc-700 ml-1 uppercase">m</span> {duration%60}<span className="text-xs text-zinc-700 ml-1 uppercase">s</span></div>
                      </div>
                      <input type="range" min="30" max="600" step="10" value={duration} onChange={e => setDuration(parseInt(e.target.value))} className="w-full h-1.5 bg-white/5 accent-brand rounded-full cursor-none appearance-none" />
                   </section>

                   <div className="pt-10">
                      <button onClick={startGeneration} disabled={isProcessing} className={`w-full py-8 rounded-[2rem] text-sm font-black uppercase tracking-[0.3em] shadow-2xl transition-all ${isQuotaExhausted ? 'bg-zinc-800 text-zinc-500 grayscale' : 'bg-brand text-white shadow-brand/40 hover:scale-[1.02] active:scale-[0.98]'}`}>
                        {isProcessing ? 'Synthesizing...' : 'Synthesize Audio'}
                      </button>
                      <p className="text-center text-[9px] text-zinc-800 font-bold uppercase tracking-widest mt-6">{isQuotaExhausted ? '📚 Using Local Presets' : '⚡ Connected to Cloud AI'}</p>
                   </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === AppState.DASHBOARD && (
            <div className="space-y-16 py-10 animate-in fade-in duration-700">
              <header className="flex justify-between items-end border-b border-white/5 pb-10">
                <h2 className="text-5xl font-black tracking-tighter">Archive</h2>
              </header>

              {projects.length === 0 ? (
                <div className="text-center py-48 border-4 border-dashed border-white/5 rounded-[4rem]">
                  <p className="text-zinc-800 text-sm font-black uppercase tracking-[0.5em]">Empty Workspace</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 gap-6">
                  {projects.map(p => (
                    <div key={p.id} className="glass p-10 rounded-[3rem] border border-white/5 hover:border-white/10 transition-all group">
                      <div className="flex items-start justify-between mb-10">
                        <div>
                          <h4 className="text-3xl font-black tracking-tighter text-white">{p.title}</h4>
                          <div className="text-[10px] font-bold text-zinc-600 uppercase tracking-widest mt-2">{p.genres.join(', ')} • {new Date(p.createdAt).toLocaleDateString()}</div>
                        </div>
                        {p.metadata && <span className="text-brand font-black text-xs uppercase tracking-widest">{p.metadata.mood}</span>}
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {p.tracks.map((t) => (
                          <div key={t.id} className="bg-black/40 border border-white/5 p-6 rounded-[2rem] space-y-6">
                             <div className="aspect-video bg-zinc-900 rounded-2xl overflow-hidden relative group/video">
                                {t.videoUrl ? (
                                  <video src={t.videoUrl} className="w-full h-full object-cover" loop muted />
                                ) : (
                                  <div className="w-full h-full flex items-center justify-center opacity-10 text-4xl">🎵</div>
                                )}
                                <div className="absolute inset-0 bg-black/40 opacity-0 group-hover/video:opacity-100 transition-opacity flex items-center justify-center">
                                   <button onClick={() => new Audio(t.audioUrl).play()} className="w-14 h-14 rounded-full bg-brand text-white flex items-center justify-center shadow-xl shadow-brand/40">▶</button>
                                </div>
                             </div>
                             <p className="text-[10px] font-black uppercase text-white truncate px-1">{t.title}</p>
                          </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>
      </main>

      {suggestion && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-deep/95 backdrop-blur-md animate-in fade-in">
          <div className={`glass w-full max-w-2xl p-12 rounded-[3rem] border space-y-10 ${isQuotaExhausted ? 'border-amber-500/30 shadow-[0_0_40px_rgba(245,158,11,0.05)]' : 'border-white/10'}`}>
            <div className="space-y-2">
              <span className={`text-[10px] font-black uppercase tracking-[0.5em] ${isQuotaExhausted ? 'text-amber-500' : 'text-brand'}`}>
                {isQuotaExhausted ? '📚 Neural Preset Mode' : '✨ AI Suggestion'}
              </span>
              <h3 className="text-4xl font-black tracking-tighter">Verify Concept</h3>
            </div>
            <div className="p-10 bg-white/[0.03] border border-white/5 rounded-3xl text-white text-lg font-medium leading-relaxed italic">
              "{suggestion.suggested}"
            </div>
            <div className="flex gap-4">
               <button onClick={applySuggestion} className="flex-1 bg-brand py-6 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl shadow-brand/20">Apply Concept</button>
               <button onClick={() => setSuggestion(null)} className="flex-1 bg-white/5 py-6 rounded-2xl font-black text-xs uppercase tracking-[0.2em] text-zinc-500">Discard</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const NavItem = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`w-full flex items-center gap-5 px-6 py-5 rounded-2xl transition-all font-black text-xs uppercase tracking-widest ${active ? 'bg-brand text-white shadow-lg shadow-brand/20' : 'text-zinc-700 hover:text-zinc-400'}`}>
    <span className="text-xl">{icon}</span>
    <span>{label}</span>
  </button>
);

const Field = ({ label, value, onChange, onSuggest, suggesting, exhausted, isTextArea, placeholder }: any) => {
  const Component = isTextArea ? 'textarea' : 'input';
  return (
    <div className="space-y-4 group">
      <div className="flex justify-between items-center px-1">
        <label className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-700 group-focus-within:text-brand transition-colors">{label}</label>
        <button onClick={onSuggest} disabled={suggesting} className={`text-[9px] font-black transition-all flex items-center gap-2 ${exhausted ? 'text-amber-500/60 hover:text-amber-500' : 'text-brand/40 hover:text-brand'}`}>
          {suggesting ? 'Processing...' : exhausted ? '📚 Neural Preset' : '✨ AI Suggest'}
        </button>
      </div>
      <Component 
        value={value} 
        onChange={(e: any) => onChange(e.target.value)} 
        placeholder={suggesting ? "Analyzing context..." : exhausted ? "Cloud limited. Presets engaged." : placeholder}
        className={`w-full bg-surface/50 border border-white/5 rounded-[1.5rem] px-6 py-5 text-white text-sm font-medium focus:outline-none focus:border-brand/40 transition-all ${isTextArea ? 'min-h-[160px] resize-none' : ''} ${suggesting ? 'opacity-30' : ''}`}
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  AppState, 
  UserSession, 
  CreationMode, 
  ProjectRecord, 
  Status, 
  TrackData,
  SuggestionState
} from './types';
import { db } from './services/dbService';
import { getFieldSuggestion, interpretIntent, generateVeoVideo, getIsCloudExhausted } from './services/geminiService';
import { generateSynthesizedAudio } from './services/audioService';

const GENRES = ["Ambient", "Cyberpunk", "Deep House", "Industrial", "Jazz Fusion", "Lo-Fi", "Neo-Classical", "Orchestral", "Phonk", "Synthwave", "Techno"];
const LANGUAGES = ["Instrumental", "English", "Japanese", "French", "Spanish", "German", "Korean"];

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.KEY_SETUP);
  const [session, setSession] = useState<UserSession | null>(null);
  const [projects, setProjects] = useState<ProjectRecord[]>([]);
  const [activeTab, setActiveTab] = useState<AppState>(AppState.HOME);

  // Form State
  const [mode, setMode] = useState<CreationMode>(CreationMode.SINGLE);
  const [numSongs, setNumSongs] = useState(3);
  const [title, setTitle] = useState('');
  const [prompt, setPrompt] = useState('');
  const [selectedGenres, setSelectedGenres] = useState<string[]>([]);
  const [duration, setDuration] = useState(120);
  const [vocalLangs, setVocalLangs] = useState<string[]>(["Instrumental"]);
  const [lyrics, setLyrics] = useState('');
  const [videoEnabled, setVideoEnabled] = useState(false);
  const [videoStyle, setVideoStyle] = useState('');

  // UI State
  const [isProcessing, setIsProcessing] = useState(false);
  const [suggestingField, setSuggestingField] = useState<string | null>(null);
  const [suggestion, setSuggestion] = useState<SuggestionState | null>(null);
  const [globalError, setGlobalError] = useState<{ message: string; isQuota: boolean; isHardLimit: boolean } | null>(null);
  const [isQuotaExhausted, setIsQuotaExhausted] = useState(false);

  useEffect(() => {
    const init = async () => {
      // @ts-ignore
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (hasKey) {
        const s = db.getSession();
        if (s) {
          setSession(s);
          setAppState(AppState.HOME);
          setProjects(db.getProjects(s.id));
        } else {
          setAppState(AppState.AUTH);
        }
      } else {
        setAppState(AppState.KEY_SETUP);
      }
    };
    init();
  }, []);

  const handleKeySetup = async () => {
    setGlobalError(null);
    setIsQuotaExhausted(false);
    // @ts-ignore
    await window.aistudio.openSelectKey();
    const s = db.getSession();
    if (s) {
      setSession(s);
      setAppState(AppState.HOME);
      setProjects(db.getProjects(s.id));
    } else {
      setAppState(AppState.AUTH);
    }
  };

  const handleAuth = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const fd = new FormData(e.currentTarget);
    const mobile = (fd.get('mobile') as string).trim();
    const name = fd.get('name') as string;
    const indianMobileRegex = /^(?:\+91)?[6789]\d{9}$/;

    if (!indianMobileRegex.test(mobile)) {
      alert("Please enter a valid Indian mobile number.");
      return;
    }

    const newSession: UserSession = { id: crypto.randomUUID(), name, mobile };
    db.saveSession(newSession);
    setSession(newSession);
    setAppState(AppState.HOME);
    setActiveTab(AppState.HOME);
    setProjects(db.getProjects(newSession.id));
  };

  const handleLogout = () => {
    db.clearSession();
    setSession(null);
    setAppState(AppState.AUTH);
    setProjects([]);
    setActiveTab(AppState.HOME);
  };

  const requestSuggestion = async (field: string, currentValue: string) => {
    if (suggestingField) return;
    setSuggestingField(field);
    setGlobalError(null);
    try {
      const context = { mode, title, prompt, selectedGenres, vocalLangs, lyrics, videoStyle };
      const suggestedText = await getFieldSuggestion(field, currentValue, context);
      setSuggestion({ field, original: currentValue, suggested: suggestedText, isActive: true });

      if (getIsCloudExhausted()) {
        setIsQuotaExhausted(true);
      }
    } catch (e: any) {
      setIsQuotaExhausted(true);
      setGlobalError({ 
        message: "Neural Cloud limited. Local Preset Engine engaged.", 
        isQuota: true,
        isHardLimit: true
      });
    } finally {
      setSuggestingField(null);
    }
  };

  const applySuggestion = () => {
    if (!suggestion) return;
    const { field, suggested } = suggestion;
    if (field === 'title') setTitle(suggested);
    if (field === 'prompt') setPrompt(suggested);
    if (field === 'lyrics') setLyrics(suggested);
    if (field === 'videoStyle') setVideoStyle(suggested);
    if (field === 'numSongs') setNumSongs(parseInt(suggested) || 3);
    setSuggestion(null);
  };

  const startGeneration = async () => {
    if (!session) {
      setAppState(AppState.AUTH);
      return;
    }

    if (!title || !prompt || selectedGenres.length === 0) {
      alert("Please provide Title, Creative Brief, and Genres.");
      return;
    }

    setIsProcessing(true);
    setGlobalError(null);
    const projectId = crypto.randomUUID();
    const newProject: ProjectRecord = {
      id: projectId,
      userId: session.id, // Safely accessing session.id now
      mode, title, prompt, 
      genres: selectedGenres,
      durationSeconds: duration,
      vocalLanguages: vocalLangs,
      lyrics,
      artistReferences: [],
      videoEnabled,
      videoStyle,
      tracks: [],
      status: Status.PROCESSING,
      createdAt: Date.now()
    };

    try {
      const intent = await interpretIntent(newProject);
      newProject.metadata = intent;

      const trackCount = mode === CreationMode.ALBUM ? numSongs : 1;
      const tracks: TrackData[] = [];

      for (let i = 0; i < trackCount; i++) {
        const audioUrl = await generateSynthesizedAudio(duration);
        let videoUrl = undefined;
        if (videoEnabled && !isQuotaExhausted) {
          try {
            videoUrl = await generateVeoVideo(videoStyle || "Minimalist", selectedGenres[0], prompt);
          } catch (veoErr) {
            console.warn("Video failed, continuing with audio only.");
          }
        }
        tracks.push({
          id: crypto.randomUUID(),
          title: mode === CreationMode.ALBUM ? `${title} - Part ${i+1}` : title,
          audioUrl,
          videoUrl,
          duration
        });
      }

      newProject.tracks = tracks;
      newProject.status = Status.COMPLETED;
      await db.saveProject(newProject);
      setProjects(prev => [newProject, ...prev]);
      setActiveTab(AppState.DASHBOARD);
    } catch (e: any) {
      newProject.status = Status.FAILED;
      await db.saveProject(newProject);
      setGlobalError({ message: "Neural Synthesis Interrupted. Try a shorter track.", isQuota: false, isHardLimit: false });
    } finally {
      setIsProcessing(false);
      setIsQuotaExhausted(getIsCloudExhausted());
    }
  };

  if (appState === AppState.KEY_SETUP) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-deep p-6">
        <div className="glass w-full max-w-lg p-12 rounded-[3rem] space-y-10 border border-white/5 shadow-2xl text-center">
          <div className="space-y-4">
            <h1 className="text-4xl font-black tracking-tighter text-white">Neural Uplink</h1>
