        <div className="p-8 border-t border-white/5 space-y-6">
          <button onClick={handleKeySetup} className="w-full text-[10px] uppercase font-black py-3 border border-brand/20 rounded-xl bg-brand/5 text-brand hover:text-white transition-all">Credentials</button>
